
"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogTitle, DialogDescription, DialogHeader } from "@/components/ui/dialog";
import {
  Zap, Loader2, Navigation, Timer, Flag, Trophy, MapPin, Clock, Gauge, Radio, StopCircle, ShieldAlert, ChevronRight, Map as MapIcon, RotateCcw
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection, query, where, getCountFromServer } from "firebase/firestore";
import { useDriving } from "@/context/driving-context";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-black rounded-[2rem] animate-pulse" />
});

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance,
    runMode, dragTime, isDragFinished, isDragActive, countdown, isJumpStart,
    isNavigating, currentCoords, heading, routePoints,
    startTrip, stopTrip, resetTrip, requestWakeLock, setRunMode
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  const [liveDragTimer, setLiveDragTimer] = useState(0);
  
  const requestRef = useRef<number>(undefined);
  const startTimeRef = useRef<number>(undefined);

  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  // Live timer for drag races
  useEffect(() => {
    const animate = () => {
      if (startTimeRef.current) {
        setLiveDragTimer((performance.now() - startTimeRef.current) / 1000);
      }
      requestRef.current = requestAnimationFrame(animate);
    };

    if (isDragActive) {
      startTimeRef.current = performance.now();
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      startTimeRef.current = undefined;
      if (!isDragFinished) setLiveDragTimer(0);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isDragActive, isDragFinished]);

  const isWaitingForStart = isDriving && !isDragActive && !isDragFinished && 
    (runMode !== 'free') && !isJumpStart;

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    try {
      const publicRunsCol = collection(db, "public_runs");
      const runTypeLabel = runMode === 'free' ? 'Top Speed' : runMode;
      const val = (runMode === 'free' || !dragTime) ? peakSpeed : dragTime;

      if (!val || val <= 0) {
        setIsRankingLoading(false);
        return;
      }

      const cityQuery = query(
        publicRunsCol, 
        where("city", "==", profile.city || "Prishtinë"), 
        where("runType", "==", runTypeLabel), 
        runMode === 'free' ? where("peakSpeedKmH", ">", val) : where("dragTime", "<", val)
      );
      const citySnapshot = await getCountFromServer(cityQuery);
      setCityRank(citySnapshot.data().count + 1);
    } catch (e) {
      console.error(e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setShowSummary(true);
      calculateRanks();
    }
  }, [isDragFinished, mounted]);

  const handleStartMission = () => {
    if (runMode !== 'free' && speed > 2) {
      toast({ variant: "destructive", title: "GABIM", description: "Ndalo makinën plotësisht për të filluar testin." });
      return;
    }
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    if (isDragFinished || runMode === 'free') {
      setShowSummary(true);
      calculateRanks();
    }
    stopTrip();
  };

  const handleQuickReport = () => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "GPS GABIM", description: "Lokacioni nuk është përcaktuar ende." });
      return;
    }
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type: 'Radar',
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: "Raport Live",
      city: profile?.city || "Kosovë",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });
    toast({ title: "U RAPORTUA!", description: "Radari u shënua në hartë." });
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Kosovë",
      runType: runMode === 'free' ? 'Top Speed' : runMode,
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };

    addDocumentNonBlocking(collection(db, "users", user.uid, "runs"), runData);
    addDocumentNonBlocking(collection(db, "public_runs"), runData);

    toast({ title: "REKORD I RI!", description: "Gara u ruajt me sukses në Ranking." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  // Gauge constants
  const size = 320;
  const strokeWidth = 10;
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;
  // Arc calculation: Start from bottom-left (-135 deg) to bottom-right (135 deg)
  const arcLength = circumference * (270 / 360);
  const progressOffset = arcLength - (Math.min(speed, 280) / 280) * arcLength;

  return (
    <div className="flex flex-col min-h-screen bg-black text-white pb-24 overflow-x-hidden safe-top relative">
      
      {/* Quick Report Floating Button */}
      <div className="absolute right-6 top-10 z-50">
        <Button onClick={handleQuickReport} size="icon" className="w-12 h-12 rounded-2xl bg-white/5 border border-white/10 text-white backdrop-blur-xl">
          <Radio className="w-6 h-6" />
        </Button>
      </div>

      {/* Mode Selector */}
      {!isDriving && (
        <div className="px-6 mt-6 flex gap-2 overflow-x-auto no-scrollbar">
          {['free', '0-60', '0-100', '100-200', '1/4mile'].map((mode) => (
            <button
              key={mode}
              onClick={() => setRunMode(mode as any)}
              className={cn(
                "px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest whitespace-nowrap transition-all border",
                runMode === mode 
                  ? "bg-white text-black border-white" 
                  : "bg-white/5 border-white/5 text-white/40"
              )}
            >
              {mode === 'free' ? 'TOP SPEED' : mode}
            </button>
          ))}
        </div>
      )}

      {/* The Digital Cockpit (Based on User's Image) */}
      <div className="flex-1 flex flex-col items-center justify-center p-6 relative">
        <div className="relative w-[340px] h-[340px] flex items-center justify-center bg-zinc-900/20 rounded-[3rem] shadow-[inset_0_0_100px_rgba(0,0,0,0.5)]">
          
          <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="rotate-[135deg]">
            {/* Background Track */}
            <circle
              cx={size / 2}
              cy={size / 2}
              r={radius}
              fill="transparent"
              stroke="rgba(255,255,255,0.1)"
              strokeWidth={strokeWidth}
              strokeDasharray={`${arcLength} ${circumference}`}
              strokeLinecap="round"
            />
            {/* Ticks */}
            {Array.from({ length: 100 }).map((_, i) => {
              const angle = (i * 2.7) - 135;
              const isMajor = i % 10 === 0;
              const x1 = size / 2 + (radius - 15) * Math.cos((angle * Math.PI) / 180);
              const y1 = size / 2 + (radius - 15) * Math.sin((angle * Math.PI) / 180);
              const x2 = size / 2 + (radius - 5) * Math.cos((angle * Math.PI) / 180);
              const y2 = size / 2 + (radius - 5) * Math.sin((angle * Math.PI) / 180);
              return (
                <line
                  key={i}
                  x1={x1}
                  y1={y1}
                  x2={x2}
                  y2={y2}
                  stroke={isMajor ? "rgba(255,255,255,0.4)" : "rgba(255,255,255,0.15)"}
                  strokeWidth={isMajor ? 2 : 1}
                  transform={`rotate(${-135} ${size / 2} ${size / 2})`}
                />
              );
            })}
            {/* Speed Progress Arc */}
            <circle
              cx={size / 2}
              cy={size / 2}
              r={radius}
              fill="transparent"
              stroke="white"
              strokeWidth={strokeWidth}
              strokeDasharray={`${arcLength} ${circumference}`}
              strokeDashoffset={progressOffset}
              strokeLinecap="round"
              className="transition-all duration-300 ease-out"
            />
          </svg>

          {/* Central Information */}
          <div className="absolute inset-0 flex flex-col items-center justify-center">
            {isJumpStart && (
              <Badge variant="destructive" className="mb-2 animate-pulse uppercase font-black text-[10px]">JUMP START</Badge>
            )}
            
            <div className="flex flex-col items-center">
              <span className="text-8xl font-light tracking-tighter tabular-nums leading-none">
                {speed}
              </span>
              <span className="text-sm font-medium text-white/40 uppercase tracking-widest mt-2">km/h</span>
            </div>

            <div className="mt-8">
               <span className="text-sm font-bold text-white/60 tracking-widest tabular-nums">
                 {tripDistance >= 1000 ? `${(tripDistance / 1000).toFixed(1)} km` : `${Math.round(tripDistance)} m`}
               </span>
            </div>
          </div>

          {/* F1 Countdown Christmas Tree */}
          {isWaitingForStart && (
            <div className="absolute -bottom-10 left-1/2 -translate-x-1/2 flex items-center gap-3 bg-black/80 backdrop-blur-2xl px-6 py-3 rounded-2xl border border-white/10">
              {[1, 2, 3, 4, 5].map((i) => (
                <div key={i} className={cn(
                  "w-6 h-6 rounded-full border transition-all duration-300",
                  countdown >= i ? "bg-red-600 border-red-500 shadow-[0_0_15px_rgba(220,38,38,0.5)]" : "bg-zinc-800 border-white/5"
                )} />
              ))}
              <div className={cn(
                "w-8 h-8 rounded-full border transition-all duration-500",
                countdown >= 6 ? "bg-green-500 border-green-400 shadow-[0_0_20px_rgba(34,197,94,0.8)]" : "bg-zinc-800 border-white/5"
              )} />
            </div>
          )}
        </div>

        {/* Telemetry Stats */}
        <div className="w-full max-w-[340px] grid grid-cols-2 gap-4 mt-20">
          <div className="bg-white/5 border border-white/5 p-4 rounded-3xl flex flex-col items-center">
            <Timer className="w-4 h-4 text-white/20 mb-2" />
            <span className="text-[8px] font-black uppercase text-white/40 tracking-widest">SESSION TIME</span>
            <span className="text-lg font-bold italic tabular-nums">{tripTime.toFixed(1)}s</span>
          </div>
          <div className="bg-white/5 border border-white/5 p-4 rounded-3xl flex flex-col items-center">
            <Trophy className="w-4 h-4 text-white/20 mb-2" />
            <span className="text-[8px] font-black uppercase text-white/40 tracking-widest">PEAK SPEED</span>
            <span className="text-lg font-bold italic tabular-nums text-red-500">{peakSpeed} <span className="text-[10px]">km/h</span></span>
          </div>
        </div>

        {/* Action Button */}
        <div className="w-full max-w-[340px] mt-8">
           <Button
             onClick={isDriving ? handleStopMission : handleStartMission}
             className={cn(
               "w-full h-16 rounded-3xl font-black text-sm uppercase tracking-widest transition-all",
               isDriving 
                ? "bg-zinc-900 border border-white/10 text-white" 
                : "bg-white text-black hover:bg-white/90"
             )}
           >
             {isDriving ? (
               <div className="flex items-center gap-2"><StopCircle className="w-5 h-5" /> STOP MISSION</div>
             ) : (
               <div className="flex items-center gap-2"><Zap className="w-5 h-5 fill-current" /> START {runMode.toUpperCase()}</div>
             )}
           </Button>
           
           {isDriving && (
             <Button 
               variant="ghost" 
               onClick={resetTrip}
               className="w-full mt-4 h-10 rounded-2xl font-black text-[10px] uppercase tracking-widest text-zinc-600 hover:text-white"
             >
               <RotateCcw className="w-3 mr-2" /> RESET TELEMETRY
             </Button>
           )}
        </div>
      </div>

      {/* Result Summary Dialog */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-zinc-950 border-white/10 w-[94%] max-w-sm rounded-[2.5rem] p-8">
          <DialogHeader>
            <DialogTitle className="text-2xl font-black italic tracking-tighter text-center uppercase">REZULTATI</DialogTitle>
            <DialogDescription className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mt-2 text-center">
              {runMode === 'free' ? 'SESSION TOP SPEED' : `${runMode} PERFORMANCE TEST`}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-6 mt-4">
            <div className="bg-white/5 p-8 rounded-[2rem] border border-white/5 text-center">
              <span className="text-6xl font-black text-white italic tabular-nums leading-none">
                {(runMode === 'free' || !dragTime) ? peakSpeed : dragTime?.toFixed(2)}
              </span>
              <span className="text-xl font-black text-red-600 ml-2 italic">
                {(runMode === 'free' || !dragTime) ? 'km/h' : 's'}
              </span>
              
              <div className="mt-4 flex items-center justify-center gap-2 text-[10px] font-black text-white/40 uppercase tracking-widest">
                <MapPin className="w-3 h-3" /> {profile?.city || 'PRISHTINË'}
              </div>
            </div>

            <div className="h-40 w-full rounded-[1.5rem] overflow-hidden border border-white/5 relative">
               <RouteMap points={routePoints} />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <Button onClick={handleSaveRun} disabled={isSaving} className="h-14 bg-white text-black rounded-2xl font-black uppercase text-[10px] tracking-widest">
                {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "RUAJ"}
              </Button>
              <Button variant="outline" className="h-14 border-white/10 rounded-2xl font-black uppercase text-[10px] tracking-widest" onClick={() => { setShowSummary(false); resetTrip(); }}>
                ANULO
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <BottomNav />
    </div>
  );
}
